content:
{
  "sentences": [
    {
      "text": "我想試穿這件黑色的上衣。",
      "pinyin": "Wǒ xiǎng shì chuān zhè jiàn hēisè de shàngyī.",
      "pinyin_numeric": "wo3 xiang3 shi4 chuan1 zhe4 jian4 hei1 se4 de0 shang4 yi1",
      "translation_en": "I want to try on this black top.",
      "translation_ko": "이 검은색 상의를 입어보고 싶습니다."
    },
    {
      "text": "這件白色的褲子太大了，有沒有小號的？",
      "pinyin": "Zhè jiàn báisè de kùzi tài dà le, yǒu méiyǒu xiǎohào de?",
      "pinyin_numeric": "zhe4 jian4 bai2 se4 de0 ku4 zi5 tai4 da4 le0, you3 mei2 you3 xiao3 hao4 de0?",
      "translation_en": "These white pants are too big. Do you have a small size?",
      "translation_ko": "이 흰색 바지는 너무 커요. 작은 사이즈가 있나요?"
    },
    {
      "text": "我穿中號的藍色外套，很舒服。",
      "pinyin": "Wǒ chuān zhōnghào de lánsè wàitào, hěn shūfu.",
      "pinyin_numeric": "wo3 chuan1 zhong1 hao4 de0 lan2 se4 wai4 tao4, hen3 shu1 fu5",
      "translation_en": "I wear a medium blue jacket, and it's very comfortable.",
      "translation_ko": "저는 중간 사이즈의 파란색 외투를 입는데, 아주 편안해요."
    },
    {
      "text": "這件紅色的裙子適合我嗎？",
      "pinyin": "Zhè jiàn hóngsè de qúnzi shìhé wǒ ma?",
      "pinyin_numeric": "zhe4 jian4 hong2 se4 de0 qun2 zi5 shi4 he2 wo3 ma0?",
      "translation_en": "Does this red skirt suit me?",
      "translation_ko": "이 빨간색 치마가 저에게 어울리나요?"
    },
    {
      "text": "這雙灰色的鞋子太小了，我想試穿大號的。",
      "pinyin": "Zhè shuāng huīsè de xiézi tài xiǎo le, wǒ xiǎng shì chuān dàhào de.",
      "pinyin_numeric": "zhe4 shuang1 hui1 se4 de0 xie2 zi5 tai4 xiao3 le0, wo3 xiang3 shi4 chuan1 da4 hao4 de0.",
      "translation_en": "These gray shoes are too small. I want to try on a large size.",
      "translation_ko": "이 회색 신발이 너무 작아요. 큰 사이즈를 신어보고 싶습니다."
    },
    {
      "text": "這件黃色的上衣很漂亮，可是太貴了。",
      "pinyin": "Zhè jiàn huángsè de shàngyī hěn piàoliang, kěshì tài guì le.",
      "pinyin_numeric": "zhe4 jian4 huang2 se4 de0 shang4 yi1 hen3 piao4 liang5, ke3 shi4 tai4 gui4 le0.",
      "translation_en": "This yellow top is very pretty, but it's too expensive.",
      "translation_ko": "이 노란색 상의는 예쁜데 너무 비싸요."
    },
    {
      "text": "這件綠色的外套可以打折嗎？",
      "pinyin": "Zhè jiàn lǜsè de wàitào kěyǐ dǎzhé ma?",
      "pinyin_numeric": "zhe4 jian4 lv4 se4 de0 wai4 tao4 ke3 yi3 da3 zhe2 ma0?",
      "translation_en": "Can this green jacket be discounted?",
      "translation_ko": "이 초록색 외투를 할인해 주실 수 있나요?"
    },
    {
      "text": "我穿黑色的褲子，你穿白色的裙子，好不好？",
      "pinyin": "Wǒ chuān hēisè de kùzi, nǐ chuān báisè de qúnzi, hǎo bù hǎo?",
      "pinyin_numeric": "wo3 chuan1 hei1 se4 de0 ku4 zi5, ni3 chuan1 bai2 se4 de0 qun2 zi5, hao3 bu4 hao3?",
      "translation_en": "I'll wear black pants, and you wear a white skirt, okay?",
      "translation_ko": "제가 검은색 바지를 입고, 당신이 흰색 치마를 입는 게 어때요?"
    },
    {
      "text": "這件藍色的上衣很合身，我買了。",
      "pinyin": "Zhè jiàn lánsè de shàngyī hěn héshēn, wǒ mǎi le.",
      "pinyin_numeric": "zhe4 jian4 lan2 se4 de0 shang4 yi1 hen3 he2 shen1, wo3 mai3 le0.",
      "translation_en": "This blue top fits well, so I'll buy it.",
      "translation_ko": "이 파란색 상의가 잘 맞아서 샀어요."
    },
    {
      "text": "這雙紅色的襪子很便宜，我買兩雙。",
      "pinyin": "Zhè shuāng hóngsè de wàzi hěn piányi, wǒ mǎi liǎng shuāng.",
      "pinyin_numeric": "zhe4 shuang1 hong2 se4 de0 wa4 zi5 hen3 pian2 yi5, wo3 mai3 liang3 shuang1.",
      "translation_en": "These red socks are very cheap; I'll buy two pairs.",
      "translation_ko": "이 빨간색 양말은 아주 싸서 두 켤레 샀어요."
    }
  ]
}
